hooks.command:
if [ -f .claude/.pending-verification ]; then
python << 'PYEOF'
import json
print(json.dumps({
    "continue": False,
    "stopReason": "本轮修改了代码、配置或文档，请先完成交付验证（运行测试、lint/typecheck、功能验证或检查TodoWrite状态）并报告结果后再结束。验证完成并通过后，执行: rm .claude/.pending-verification 清除标记。",
    "hookSpecificOutput": {
        "hookEventName": "Stop",
        "additionalContext": "本轮修改了代码/配置/文档但未完成交付验证。请继续工作：运行相关测试、lint或typecheck、进行功能验证，或检查TodoWrite任务完成状态。验证通过后，用Bash删除标记文件 rm .claude/.pending-verification，然后可以正常结束。"
    }
}, ensure_ascii=False))
PYEOF
fi
